package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.Reader;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private Path mockPath;
    private Charset charset;
    private CSVFormat format;
    private BufferedReader mockReader;

    @BeforeEach
    void setUp() throws IOException {
        mockPath = mock(Path.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
        mockReader = mock(BufferedReader.class);
    }

    @Test
    void parse_shouldReturnCSVParser_whenValidPathCharsetAndFormat() throws IOException {
        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedReader(mockPath, charset)).thenReturn(mockReader);
            try (MockedStatic<CSVParser> csvParserStatic = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
                csvParserStatic.when(() -> CSVParser.parse(mockReader, format)).thenCallRealMethod();
                CSVParser result = CSVParser.parse(mockPath, charset, format);
                assertNotNull(result);
                assertTrue(result instanceof CSVParser);
            }
        }
    }

    @Test
    void parse_shouldThrowNullPointerException_whenPathIsNull() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(null, charset, format));
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_shouldThrowNullPointerException_whenFormatIsNull() {
        NullPointerException ex = assertThrows(NullPointerException.class,
                () -> CSVParser.parse(mockPath, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_shouldThrowIOException_whenFilesNewBufferedReaderThrows() throws IOException {
        try (MockedStatic<Files> filesMockedStatic = Mockito.mockStatic(Files.class)) {
            filesMockedStatic.when(() -> Files.newBufferedReader(mockPath, charset)).thenThrow(new IOException("io error"));
            IOException ex = assertThrows(IOException.class, () -> CSVParser.parse(mockPath, charset, format));
            assertEquals("io error", ex.getMessage());
        }
    }

}
